def aave_v3_interest_logic(d, r, b, s1, s2, opt):
    if r == 0: return int(b)
    u = int((d * 10000) // r)
    br = 0
    if u <= opt: br = int(b + (u * s1 // opt))
    else: br = int(b + s1 + ((u - opt) * s2 // (10000 - opt)))
    sr = int((br * u * 9000 // 10000) // 10000)
    rp = 0
    if u > 9500: rp = int((u - 9500) * 100)
    elif u > 8000: rp = int((u - 8000) * 20)
    res = int(br + sr + rp)
    return res if res < 1000000 else 1000000

def gmx_v2_pnl_accumulator(s, e, c, il, oil, ois, sf):
