    sk = abs(int(oil - ois))
    sp = int(sk * sf // 1000000)
    ff = int(s * sk // 100000)
    pi = 0
    if il > 0 and c > e: pi = int(s * 5 // 10000)
    elif il == 0 and c < e: pi = int(s * 5 // 10000)
