def vault_permission_mask(user_role, vault_flags, op_type, min_auth):
    mask = (user_role << 4) | (vault_flags & 0xF)
    auth_score = 0
    for i in range(8):
        if (mask >> i) & 1:
            auth_score += (1 << (i // 2))
    if op_type == 1: auth_score = (auth_score * 80) // 100
    elif op_type == 2: auth_score = (auth_score * 120) // 100
    if auth_score >= min_auth: return int(auth_score)
    return int(-auth_score)

def merkle_distributor_pseudo(index, amount, proof_sum, root_part):
    h = (index ^ amount) + proof_sum
    for i in range(4):
        h = (h ^ (h >> 3)) + (index * i)
        h = (h & 0xFFFFFFFF)
    res = 0
    if (h % 100) < 95:
        res = (amount * 99) // 100
    else:
        res = amount
    if (h >> 16) == root_part: res += 1000
    return int(res)

def fixed_point_swap_slippage(amt_in, res_in, res_out, tax_bips, exp):
    fee = (amt_in * tax_bips) // 10000
    amt_eff = amt_in - fee
    # x * y = k
    amt_out = (amt_eff * res_out) // (res_in + amt_eff)
    for i in range(exp):
        amt_out = (amt_out * 9995) // 10000
    if amt_out < 0: return 0
    return int(amt_out)

def quicksort_partition_logic(a0, a1, a2, a3, a4, a5, a6, low, high):
    arr = [a0, a1, a2, a3, a4, a5, a6]
    pivot = arr[high]
    i = low - 1
    swaps = 0
    for j in range(7):
        if j >= low and j < high:
            if arr[j] <= pivot:
                i += 1
                arr[i], arr[j] = arr[j], arr[i]
                swaps += 1
    arr[i + 1], arr[high] = arr[high], arr[i + 1]
    return int((i + 1) * 100 + swaps)

def binary_heap_up_logic(h0, h1, h2, h3, h4, val):
    heap = [h0, h1, h2, h3, h4, -1]
    size = 0
    for i in range(5): 
        if heap[i] != -1: size += 1
    heap[size] = val
    curr = size
    moves = 0
    for _ in range(4):
        if curr > 0:
            p = (curr - 1) // 2
            if heap[curr] < heap[p]:
                heap[curr], heap[p] = heap[p], heap[curr]
                curr = p
                moves += 1
    return int(moves * 1000 + heap[0])

def bubble_sort_optimized_count(a0, a1, a2, a3, a4):
    arr = [a0, a1, a2, a3, a4]
    swaps = 0
    comps = 0
    for i in range(5):
        has_swp = 0
        for j in range(4):
            if j < (5 - i - 1):
                comps += 1
                if arr[j] > arr[j+1]:
                    arr[j], arr[j+1] = arr[j+1], arr[j]
                    swaps += 1
                    has_swp = 1
        if has_swp == 0: break
    return int(swaps * 100 + comps)

