def shell_sort_step_logic(a0, a1, a2, a3, a4):
    arr = [a0, a1, a2, a3, a4]
    ts = 0
    gap = 2
    for _ in range(2):
        if gap > 0:
            for i in range(5):
                if i >= gap:
                    temp = arr[i]
                    j = i
                    for _ in range(5):
                        if j >= gap and arr[j - gap] > temp:
                            arr[j] = arr[j - gap]
                            j -= gap
                            ts += 1
                    arr[j] = temp
            gap //= 2
    return int(ts * 10 + arr[0])

def binary_search_bounds_logic(a0, a1, a2, a3, a4, a5, a6, target):
    arr = [a0, a1, a2, a3, a4, a5, a6]
    low, high = 0, 6
    f_idx = -1
    for _ in range(8):
        if low <= high:
            mid = (low + high) // 2
            if arr[mid] >= target:
                if arr[mid] == target: f_idx = mid
                high = mid - 1
            else: low = mid + 1
    low2, high2 = 0, 6
    l_idx = -1
    for _ in range(8):
        if low2 <= high2:
            mid2 = (low2 + high2) // 2
            if arr[mid2] <= target:
                if arr[mid2] == target: l_idx = mid2
                low2 = mid2 + 1
            else: high2 = mid2 - 1
    if f_idx == -1: return 0
    return int((l_idx - f_idx + 1) * 100 + f_idx)

def knapsack_dp_compressed(w0, w1, w2, v0, v1, v2, cap):
    weights = [w0, w1, w2]
    values = [v0, v1, v2]
    dp = [0] * 11
    for i in range(3):
        curr_w = weights[i]
        curr_v = values[i]
        for j in range(10, -1, -1):
            if j >= curr_w:
                new_v = dp[j - curr_w] + curr_v
                if new_v > dp[j]: dp[j] = new_v
    res = dp[cap]
    for i in range(11): res += (dp[i] & 1)
    return int(res)

