def discrete_bayes_updater(prior_a, prior_b, cond_e_a, cond_e_b):
    p_e = (prior_a * cond_e_a) + (prior_b * cond_e_b)
    if p_e == 0: return 0
    posterior_a = (prior_a * cond_e_a * 10000) // p_e
    posterior_b = (prior_b * cond_e_b * 10000) // p_e
