def anova_f_test_logic(g1_s, g1_n, g2_s, g2_n, total_ss):
    m1, m2 = g1_s // g1_n, g2_s // g2_n
    gm = (g1_s + g2_s) // (g1_n + g2_n)
    ssb = g1_n * (m1 - gm)**2 + g2_n * (m2 - gm)**2
    ssw = total_ss - ssb
    if ssw <= 0: return int(gm)
    return int((ssb * 100) // ssw + gm)

