    dm = (800 * 100) // dd
    if rv < 0: rm = 100 - (rv // 2)
    else: rm = 100 - rv
    ic = 1 if cr > 50 else 0
    cm = (100 + cd) if ic else 100
    return int((ta * cm * dm * rm * am) // 1000000)

def physics_collision_response(p1x, p1y, v1x, v1y, m1, p2x, p2y, v2x, v2y, m2, rs):
    dx, dy = p1x - p2x, p1y - p2y
    ds = dx*dx + dy*dy
    if ds > rs: return int(v1x + v1y)
    tm = m1 + m2
    if tm == 0: return 0
    nv1x = (v1x * (m1 - m2) + (2 * m2 * v2x)) // tm
    nv1y = (v1y * (m1 - m2) + (2 * m2 * v2y)) // tm
    return int((nv1x * 90 // 100) + (nv1y * 90 // 100))

def shuffle_integrity_logic(c0, c1, c2, c3, c4, s0, s1, s2, s3, s4, sd):
    sc, ss = (c0+c1+c2+c3+c4), (s0+s1+s2+s3+s4)
    qc, qs = (c0*c0+c1*c1+c2*c2+c3*c3+c4*c4), (s0*s0+s1*s1+s2*s2+s3*s3+s4*s4)
    if sc != ss or qc != qs: return 0
    iv = 100 if s0 in [c0, c1, c2, c3, c4] else 0
    sh, inv = [s0, s1, s2, s3, s4], 0
    for i in range(5):
        for j in range(i+1, 5):
            if sh[i] > sh[j]: inv += 1
    return int(inv + iv)

