def evolutionary_game_replicator(pop_a, pop_b, p_aa, p_ab, p_ba, p_bb):
    avg_a = (pop_a * p_aa + pop_b * p_ab) // 100
    avg_b = (pop_a * p_ba + pop_b * p_bb) // 100
    total_avg = (pop_a * avg_a + pop_b * avg_b) // 100
    if total_avg == 0: return int(pop_a)
    new_pop_a = (pop_a * avg_a) // total_avg
    return int(new_pop_a)

